#include <stdlib.h>

int min(int a, int b) { return a < b ? a : b; }

int frogJump(int* height, int heightSize) {
    if (heightSize == 0) return 0;
    int* dp = (int*)malloc(heightSize * sizeof(int));
    dp[0] = 0;
    for (int i = 1; i < heightSize; i++) {
        if (i == 1) dp[i] = abs(height[i] - height[i - 1]);
        else dp[i] = min(dp[i - 1] + abs(height[i] - height[i - 1]), dp[i - 2] + abs(height[i] - height[i - 2]));
    }
    int result = dp[heightSize - 1];
    free(dp);
    return result;
}

int main() {
    int height[] = {30, 10, 60, 10, 60, 50};
    int heightSize = sizeof(height) / sizeof(height[0]);
    printf("%d\n", frogJump(height, heightSize));
    return 0;
}

